<?php/** * AquaLuxe WooCommerce Class * * @package AquaLuxe * @since 1.0.0 */if ( ! defined( 'ABSPATH' ) ) {    exit; // Exit if accessed directly}/** * AquaLuxe WooCommerce Class */class AquaLuxe_WooCommerce {    /**     * Instance of this class     *     * @var AquaLuxe_WooCommerce     */    private static $instance;    /**     * Main WooCommerce instance     *     * @return AquaLuxe_WooCommerce     */    public static function instance() {        if ( ! isset( self::$instance ) && ! ( self::$instance instanceof AquaLuxe_WooCommerce ) ) {            self::$instance = new AquaLuxe_WooCommerce();            self::$instance->init_hooks();        }        return self::$instance;    }    /**     * Initialize hooks     *     * @return void     */    private function init_hooks() {        // Setup WooCommerce        add_action( 'after_setup_theme', array( $this, 'setup' ) );                // Enqueue styles and scripts        add_action( 'wp_enqueue_scripts', array( $this, 'enqueue_styles' ) );        add_action( 'wp_enqueue_scripts', array( $this, 'enqueue_scripts' ) );                // Remove default WooCommerce styles        add_filter( 'woocommerce_enqueue_styles', '__return_empty_array' );                // Disable WooCommerce sidebar on certain pages        add_action( 'wp', array( $this, 'disable_woocommerce_sidebar' ) );                // Change number of products per row        add_filter( 'loop_shop_columns', array( $this, 'loop_columns' ) );                // Change number of products per page        add_filter( 'loop_shop_per_page', array( $this, 'products_per_page' ) );                // Change related products args        add_filter( 'woocommerce_output_related_products_args', array( $this, 'related_products_args' ) );                // Change upsell products args        add_filter( 'woocommerce_upsell_display_args', array( $this, 'upsell_products_args' ) );                // Change cross sell products args        add_filter( 'woocommerce_cross_sells_columns', array( $this, 'cross_sells_columns' ) );        add_filter( 'woocommerce_cross_sells_total', array( $this, 'cross_sells_total' ) );                // Add product gallery support        add_action( 'after_setup_theme', array( $this, 'product_gallery_support' ) );    }    /**     * Setup WooCommerce     *     * @return void     */    public function setup() {        // Add WooCommerce support        add_theme_support( 'woocommerce' );                // Add product gallery support        add_theme_support( 'wc-product-gallery-zoom' );        add_theme_support( 'wc-product-gallery-lightbox' );        add_theme_support( 'wc-product-gallery-slider' );    }    /**     * Enqueue styles     *     * @return void     */    public function enqueue_styles() {        wp_enqueue_style( 'aqualuxe-woocommerce', AQUALUXE_ASSETS_URI . 'css/woocommerce.css', array( 'aqualuxe-style' ), AQUALUXE_VERSION );    }    /**     * Enqueue scripts     *     * @return void     */    public function enqueue_scripts() {        wp_enqueue_script( 'aqualuxe-woocommerce', AQUALUXE_ASSETS_URI . 'js/woocommerce.js', array( 'jquery' ), AQUALUXE_VERSION, true );                wp_localize_script( 'aqualuxe-woocommerce', 'aqualuxeWoocommerce', array(            'ajaxUrl'        => admin_url( 'admin-ajax.php' ),            'ajaxNonce'      => wp_create_nonce( 'aqualuxe-woocommerce-nonce' ),            'quickViewNonce' => wp_create_nonce( 'aqualuxe-quick-view-nonce' ),            'wishlistNonce'  => wp_create_nonce( 'aqualuxe-wishlist-nonce' ),            'compareNonce'   => wp_create_nonce( 'aqualuxe-compare-nonce' ),            'i18n'           => array(                'quickView'      => __( 'Quick View', 'aqualuxe' ),                'wishlist'       => __( 'Wishlist', 'aqualuxe' ),                'compare'        => __( 'Compare', 'aqualuxe' ),                'addToWishlist'  => __( 'Add to Wishlist', 'aqualuxe' ),                'removeFromWishlist' => __( 'Remove from Wishlist', 'aqualuxe' ),                'addToCompare'   => __( 'Add to Compare', 'aqualuxe' ),                'removeFromCompare'  => __( 'Remove from Compare', 'aqualuxe' ),                'loading'        => __( 'Loading...', 'aqualuxe' ),                'error'          => __( 'Error', 'aqualuxe' ),                'success'        => __( 'Success', 'aqualuxe' ),                'close'          => __( 'Close', 'aqualuxe' ),                'next'           => __( 'Next', 'aqualuxe' ),                'prev'           => __( 'Previous', 'aqualuxe' ),            ),        ) );    }    /**     * Disable WooCommerce sidebar on certain pages     *     * @return void     */    public function disable_woocommerce_sidebar() {        if ( is_product() ) {            remove_action( 'woocommerce_sidebar', 'woocommerce_get_sidebar', 10 );        }    }    /**     * Change number of products per row     *     * @return int     */    public function loop_columns() {        return aqualuxe_get_shop_columns();    }    /**     * Change number of products per page     *     * @return int     */    public function products_per_page() {        return aqualuxe_get_products_per_page();    }    /**     * Change related products args     *     * @param array $args Related products args     * @return array     */    public function related_products_args( $args ) {        $args['posts_per_page'] = aqualuxe_get_related_products_count();        $args['columns'] = aqualuxe_get_shop_columns();                return $args;    }    /**     * Change upsell products args     *     * @param array $args Upsell products args     * @return array     */    public function upsell_products_args( $args ) {        $args['posts_per_page'] = aqualuxe_get_related_products_count();        $args['columns'] = aqualuxe_get_shop_columns();                return $args;    }    /**     * Change cross sell products columns     *     * @return int     */    public function cross_sells_columns() {        return aqualuxe_get_shop_columns();    }    /**     * Change cross sell products total     *     * @return int     */    public function cross_sells_total() {        return aqualuxe_get_related_products_count();    }    /**     * Add product gallery support     *     * @return void     */    public function product_gallery_support() {        // Check if product gallery zoom is enabled        if ( aqualuxe_get_option( 'aqualuxe_product_gallery_zoom', true ) ) {            add_theme_support( 'wc-product-gallery-zoom' );        }                // Check if product gallery lightbox is enabled        if ( aqualuxe_get_option( 'aqualuxe_product_gallery_lightbox', true ) ) {            add_theme_support( 'wc-product-gallery-lightbox' );        }                // Check if product gallery slider is enabled        if ( aqualuxe_get_option( 'aqualuxe_product_gallery_slider', true ) ) {            add_theme_support( 'wc-product-gallery-slider' );        }    }}